// // This module divides the input clock frequency by 4 and inverts the output on each falling edge of the input clock signal.
module frequency_divider(  
    input wire clk,  
    input wire reset,  
    output reg q  
);  

always @(posedge clk or posedge reset) begin  
    if (reset)  
        q <= 0;  
    else  
        q <= ~q;  
end  
endmodule
